  3	const CUSTOMER_STATUS = "At-risk escalation active with executive recovery owner routing and customer-visible audit history.";
  4	
  5	export function applyBenchmarkTask(db, now) {
  6	  const request = db.workflow_requests[0];
  7	  const account = db.accounts.find((item) => item._id === request.accountId);
  8	  const ownerGroups = [...request.ownerGroups];
  9	  const timelineEvents = db.activities
 10	    .filter((item) => item.accountId === account._id && item.subjectId === request._id)
 11	    .sort((left, right) => new Date(left.occurredAt) - new Date(right.occurredAt));
 12	
 13	  const auditEvents = [
 14	    ...timelineEvents.map((activity, index) => ({
 15	      _id: `audit-${activity._id}`,
 16	      requestId: request._id,
 17	      accountId: account._id,
 18	      subjectId: request._id,
 19	      eventType: "account-activity",
 20	      summary: activity.summary,
 21	      occurredAt: activity.occurredAt,
 22	      customerVisible: false,
 23	      sequence: index + 1
 24	    })),
 25	    {
 26	      _id: `audit-${request._id}-customer-visible`,
 27	      requestId: request._id,
 28	      accountId: account._id,
 29	      subjectId: request._id,
 30	      eventType: "customer-visible-status",
 31	      summary: "Customer-visible recovery history published in the portal.",
 32	      occurredAt: now,
 33	      customerVisible: true,
 34	      sequence: timelineEvents.length + 1
 35	    }
 36	  ];
 37	
 38	  db.workflow_state = [
 39	    {
 40	      _id: `workflow-state-${request._id}`,
 41	      requestId: request._id,
 42	      accountId: account._id,
 43	      taskId: request.taskId,
 44	      title: request.title,
 45	      status: CUSTOMER_STATUS,
 46	      nextStep: "Customer Success, Legal, Finance, and Support to confirm the recovery plan by 16:00 UTC.",
 47	      riskSignals: structuredClone(request.riskSignals),
 48	      context: {
 49	        accountTier: account.tier,
 50	        contract: structuredClone(account.contract),
 51	        support: {
 52	          supportPlan: account.contract.supportPlan,
 53	          openCases: account.context.openCases
 54	        },
 55	        invoice: {
 56	          risk: account.context.invoiceRisk
 57	        },
 58	        usage: {
 59	          trend: account.context.usageTrend,
 60	          healthScore: account.context.healthScore
 61	        },
 62	        shipment: {
 63	          status: "delayed",
 64	          priority: "expedite"
 65	        },
 66	        regulatory: {
 67	          complianceFlags: structuredClone(account.context.complianceFlags),
 68	          legalReview: true
 69	        },
 70	        audit: {
 71	          timeline: auditEvents.map(({ _id, eventType, summary, occurredAt, customerVisible }) => ({
 72	            _id,
 73	            eventType,
 74	            summary,
 75	            occurredAt,
 76	            customerVisible
 77	          }))
 78	        }
 79	      },
 80	      routing: {
 81	        ownerGroups,
 82	        coordinationGroups: ["Customer Success", "Legal", "Finance", "Support"],
 83	        executiveRecoveryOwner: "Executive Sponsor"
 84	      }
 85	    }
 86	  ];
 87	
 88	  db.owner_tasks = ownerGroups.map((ownerGroup, index) => ({
 89	    _id: `owner-task-${request._id}-${slugify(ownerGroup)}`,
 90	    requestId: request._id,
 91	    accountId: account._id,
 92	    ownerGroup,
 93	    title: taskTitle(ownerGroup, account.name),
 94	    dueAt: new Date(Date.parse(now) + (index + 1) * 2 * 60 * 60 * 1000).toISOString(),
 95	    status: "open",
 96	    priority: index === 0 ? "urgent" : "high"
 97	  }));
 98	
 99	  db.customer_messages = [
100	    {
101	      _id: `customer-message-${request._id}`,
102	      requestId: request._id,
103	      accountId: account._id,
104	      channel: "portal",
105	      body: "We have activated the recovery plan for your order and are coordinating updates through the portal.",
106	      customerVisible: true,
107	      createdAt: now
108	    }
109	  ];
110	
111	  db.audit_events = auditEvents;
112	
113	  return buildPortalView(db);
114	}
115	
116	function taskTitle(ownerGroup, accountName) {
117	  switch (ownerGroup) {
118	    case "Customer Success":
119	      return `Coordinate recovery for ${accountName}`;
120	    case "Support":
121	      return `Track shipment and support updates for ${accountName}`;
122	    case "Finance":
123	      return `Review invoice risk and billing exposure for ${accountName}`;
124	    default:
125	      return `Approve executive recovery path for ${accountName}`;
126	  }
127	}
128	
129	function slugify(value) {
130	  return value.toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/^-|-$/g, "") || "task";
131	}
